if doc.custom_old_sales_order and doc.items:
    item = doc.items[0]  # assuming only one item row
    batch_id = doc.custom_old_sales_order

    # Check if batch already exists for this specific item
    existing_batch = frappe.db.exists("Batch", {
        "batch_id": batch_id,
        "item": item.item_code
    })

    if not existing_batch:
        # Create new batch
        batch = frappe.get_doc({
            "doctype": "Batch",
            "batch_id": batch_id,
            "item": item.item_code,
            "custom_new_sales_order": doc.custom_new_sales_order
        })
        batch.insert(ignore_permissions=True)
        frappe.msgprint(f"Batch {batch_id} created for item {item.item_code}")
    else:
        # Update custom_new_sales_order on existing batch (if changed)
        frappe.db.set_value("Batch", existing_batch, "custom_new_sales_order", doc.custom_new_sales_order)
        frappe.msgprint(f"Batch {batch_id} updated with new sales order {doc.custom_new_sales_order}")

    # Assign batch to the item row
    for d in doc.items:
        d.batch_no = batch_id

@frappe.whitelist()
def send(recipients, subject, message, attachments=None, doctype=None, docname=None):
    if not recipients or not subject or not message:
        frappe.throw("Recipients, subject, and message are required")

    # Parse attachments if passed as JSON string
    if attachments and isinstance(attachments, str):
        attachments = frappe.parse_json(attachments)

    attachment_list = []
    if attachments:
        for att in attachments:
            # att['fcontent'] is a hex string from the client
            pdf_bytes = bytes.fromhex(att['fcontent'])
            attachment_list.append({
                'fname': att['fname'],
                'fcontent': pdf_bytes
            })

    frappe.sendmail(
        recipients=recipients.split(','),
        subject=subject,
        message=message,
        attachments=attachment_list,
        reference_doctype=doctype,
        reference_name=docname
    )
    return "Email sent successfully"
